 28‚Üíinternal class ConstantFormatStructure<in T>(
 29‚Üí    val string: String
 30‚Üí) : NonConcatenatedFormatStructure<T> {
 31‚Üí    override fun toString(): String = "ConstantFormatStructure($string)"
 32‚Üí
 33‚Üí    override fun equals(other: Any?): Boolean = other is ConstantFormatStructure<*> && string == other.string
 34‚Üí    override fun hashCode(): Int = string.hashCode()
 35‚Üí
 36‚Üí    override fun parser(): ParserStructure<T> = ParserStructure(
 37‚Üí        operations = when {
 38‚Üí            string.isEmpty() -> emptyList()
 39‚Üí            else -> buildList {
 40‚Üí                val suffix = if (string[0].isDigit()) {
 41‚Üí                    add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(string.takeWhile { it.isDigit() }))))
 42‚Üí                    string.dropWhile { it.isDigit() }
 43‚Üí                } else {
 44‚Üí                    string
 45‚Üí                }
 46‚Üí                if (suffix.isNotEmpty()) {
 47‚Üí                    if (suffix[suffix.length - 1].isDigit()) {
 48‚Üí                        add(PlainStringParserOperation(suffix.dropLastWhile { it.isDigit() }))
 49‚Üí                        add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(suffix.takeLastWhile { it.isDigit() }))))
 50‚Üí                    } else {
 51‚Üí                        add(PlainStringParserOperation(suffix))
 52‚Üí                    }
 53‚Üí                }
 54‚Üí            }
 55‚Üí        },
 56‚Üí        followedBy = emptyList()
 57‚Üí    )
 58‚Üí
 59‚Üí    override fun formatter(): FormatterStructure<T> = ConstantStringFormatterStructure(string)
 60‚Üí}
