141‚Üíinternal class OptionalFormatStructure<in T>(
142‚Üí    val onZero: String,
143‚Üí    val format: FormatStructure<T>,
144‚Üí) : NonConcatenatedFormatStructure<T> {
145‚Üí    override fun toString(): String = "Optional($onZero, $format)"
146‚Üí
147‚Üí    private val fields = basicFormats(format).map { it.field }.distinct().map { field ->
148‚Üí        PropertyWithDefault.fromField(field)
149‚Üí    }
150‚Üí
151‚Üí    override fun equals(other: Any?): Boolean =
152‚Üí        other is OptionalFormatStructure<*> && onZero == other.onZero && format == other.format
153‚Üí
154‚Üí    override fun hashCode(): Int = 31 * onZero.hashCode() + format.hashCode()
155‚Üí
156‚Üí    override fun parser(): ParserStructure<T> = ParserStructure(
157‚Üí        operations = emptyList(),
158‚Üí        followedBy = listOf(
159‚Üí            format.parser(),
160‚Üí            listOf(
161‚Üí                ConstantFormatStructure<T>(onZero).parser(),
162‚Üí                ParserStructure(
163‚Üí                    listOf(
164‚Üí                        UnconditionalModification {
165‚Üí                            for (field in fields) {
166‚Üí                                field.assignDefault(it)
167‚Üí                            }
168‚Üí                        }
169‚Üí                    ),
170‚Üí                    emptyList()
171‚Üí                )
172‚Üí            ).concat()
173‚Üí        )
174‚Üí    )
175‚Üí
176‚Üí    override fun formatter(): FormatterStructure<T> {
177‚Üí        val formatter = format.formatter()
178‚Üí        val predicate = conjunctionPredicate(fields.map { it.isDefaultComparisonPredicate() })
179‚Üí        return ConditionalFormatter(
180‚Üí            listOf(
181‚Üí                predicate::test to ConstantStringFormatterStructure(onZero),
182‚Üí                Truth::test to formatter
183‚Üí            )
184‚Üí        )
185‚Üí    }
186‚Üí
187‚Üí    private class PropertyWithDefault<in T, E> private constructor(
188‚Üí        private val accessor: Accessor<T, E>,
189‚Üí        private val defaultValue: E
190‚Üí    ) {
191‚Üí        companion object {
192‚Üí            fun <T, E> fromField(field: FieldSpec<T, E>): PropertyWithDefault<T, E> {
193‚Üí                val default = field.defaultValue
194‚Üí                require(default != null) {
195‚Üí                    "The field '${field.name}' does not define a default value"
196‚Üí                }
197‚Üí                return PropertyWithDefault(field.accessor, default)
198‚Üí            }
199‚Üí        }
200‚Üí
201‚Üí        inline fun assignDefault(target: T) {
202‚Üí            accessor.trySetWithoutReassigning(target, defaultValue)
203‚Üí        }
204‚Üí
205‚Üí        inline fun isDefaultComparisonPredicate() = ComparisonPredicate(defaultValue, accessor::getter)
206‚Üí    }
207‚Üí}
