209‚Üíinternal sealed interface NonConcatenatedFormatStructure<in T> : FormatStructure<T>
210‚Üí
211‚Üíinternal open class ConcatenatedFormatStructure<in T>(
212‚Üí    val formats: List<NonConcatenatedFormatStructure<T>>
213‚Üí) : FormatStructure<T> {
214‚Üí    override fun toString(): String = "ConcatenatedFormatStructure(${formats.joinToString(", ")})"
215‚Üí
216‚Üí    override fun equals(other: Any?): Boolean = other is ConcatenatedFormatStructure<*> && formats == other.formats
217‚Üí
218‚Üí    override fun hashCode(): Int = formats.hashCode()
219‚Üí
220‚Üí    override fun parser(): ParserStructure<T> = formats.map { it.parser() }.concat()
221‚Üí
222‚Üí    override fun formatter(): FormatterStructure<T> {
223‚Üí        val formatters = formats.map { it.formatter() }
224‚Üí        return if (formatters.size == 1) {
225‚Üí            formatters.single()
226‚Üí        } else {
227‚Üí            ConcatenatedFormatter(formatters)
228‚Üí        }
229‚Üí    }
230‚Üí}
231‚Üí
232‚Üíinternal class CachedFormatStructure<in T>(formats: List<NonConcatenatedFormatStructure<T>>) :
233‚Üí    ConcatenatedFormatStructure<T>(formats) {
234‚Üí    private val cachedFormatter: FormatterStructure<T> by lazy { super.formatter() }
235‚Üí    private val cachedParser: ParserStructure<T> by lazy { super.parser() }
236‚Üí
237‚Üí    override fun formatter(): FormatterStructure<T> = cachedFormatter
238‚Üí
239‚Üí    override fun parser(): ParserStructure<T> = cachedParser
240‚Üí}
241‚Üí
242‚Üíprivate fun <T> basicFormats(format: FormatStructure<T>): List<FieldFormatDirective<T>> = buildList {
243‚Üí    fun rec(format: FormatStructure<T>) {
244‚Üí        when (format) {
245‚Üí            is BasicFormatStructure -> add(format.directive)
246‚Üí            is ConcatenatedFormatStructure -> format.formats.forEach { rec(it) }
247‚Üí            is ConstantFormatStructure -> {}
248‚Üí            is SignedFormatStructure -> rec(format.format)
249‚Üí            is AlternativesParsingFormatStructure -> {
250‚Üí                rec(format.mainFormat); format.formats.forEach { rec(it) }
251‚Üí            }
252‚Üí
253‚Üí            is OptionalFormatStructure -> rec(format.format)
254‚Üí        }
255‚Üí    }
256‚Üí    rec(format)
257‚Üí}
