16‚Üí@Serializable(with = UtcOffsetSerializer::class)
17‚Üípublic actual class UtcOffset(internal val zoneOffset: ZoneOffset) {
18‚Üí    public actual val totalSeconds: Int get() = zoneOffset.totalSeconds
