package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.*

/**
 * Test file to verify improved error messages include full input and have proper capitalization.
 */
class ErrorMessagesTest {

    @Test
    fun testInconsistentHourAmPmMessageIncludesFullInput() {
        // Test that "Inconsistent hour and the AM/PM marker" message includes the full input
        val format = LocalTime.Format {
            hour()
            char(' ')
            amPmMarker("AM", "PM")
        }
        val error = assertFailsWith<DateTimeFormatException> {
            format.parse("23 AM")
        }
        // The error message should mention both "23" and "AM", and ideally show the full input
        assertTrue(error.message!!.contains("23"), "Error should contain the hour value '23'")
        assertTrue(error.message!!.contains("AM"), "Error should contain the AM/PM marker 'AM'")
        // Check if the full input is mentioned
        assertTrue(
            error.message!!.contains("23 AM") || error.message!!.contains("input") || error.message!!.contains("text"),
            "Error should contain full input or reference to it"
        )
    }

    @Test
    fun testExpectedOneOfCapitalization() {
        // Test that "Expected one of" uses lowercase "one of"
        val format = LocalTime.Format {
            amPmMarker("AM", "PM")
        }

        val error = assertFailsWith<DateTimeFormatException> {
            format.parse("XM")
        }
        // Ensure the message uses lowercase "one of"
        // Look for "one of" pattern in error messages
        // This might come from nested exceptions
        val message = error.message!!.lowercase()
        // The issue specifically mentions "Position X: Expected One of" should be "Position 0: Expected one of"
        if (message.contains("expected")) {
            // If there's any "Expected" followed by "One of", check the capitalization
            val expectedPattern = Regex("expected [Oo]ne of")
            val matches = expectedPattern.findAll(error.message!!).toList()
            if (matches.isNotEmpty()) {
                // Ensure it's "one of" not "One of"
                assertFalse(
                    error.message!!.contains("One of"),
                    "Should use lowercase 'one of', not 'One of'"
                )
            }
        }
    }

    @Test
    fun testValidationInLocalDateConstructor() {
        // Test that validation errors in constructors include helpful messages
        // This tests issue #3 - validation in constructors
        val error = assertFailsWith<IllegalArgumentException> {
            LocalDate(2024, 2, 30) // Invalid day for February
        }
        assertTrue(
            error.message!!.isNotEmpty(),
            "Error message should not be empty"
        )
    }

    @Test
    fun testValidationInLocalTimeConstructor() {
        val error = assertFailsWith<IllegalArgumentException> {
            LocalTime(24, 0, 0, 0) // Invalid hour
        }
        assertTrue(
