 10‚Üí/**
 11‚Üí * Describes the commands that the parser must execute, in two portions:
 12‚Üí * * [operations], which are executed in order, and
 13‚Üí * * [followedBy], which are executed *in parallel* after [operations].
 14‚Üí *
 15‚Üí * An example of a [ParserStructure]:
 16‚Üí * ```
 17‚Üí * // number - dash - number - dash - number
 18‚Üí * //        |
 19‚Üí * //        \
 20‚Üí * //         letter 'W' - number
 21‚Üí * ParserStructure(
 22‚Üí *   listOf(numberParser),
 23‚Üí *   listOf(
 24‚Üí *     ParserStructure(
 25‚Üí *       listOf(stringParser("-"), numberParser, stringParser("-"), numberParser),
 26‚Üí *       emptyList()
 27‚Üí *     ),
 28‚Üí *     ParserStructure(
 29‚Üí *       listOf(stringParser("W"), numberParser),
 30‚Üí *       emptyList()
 31‚Üí *     ),
 32‚Üí *   )
 33‚Üí * )
 34‚Üí * ```
 35‚Üí */
 36‚Üíinternal class ParserStructure<in Output>(
 37‚Üí    val operations: List<ParserOperation<Output>>,
 38‚Üí    val followedBy: List<ParserStructure<Output>>,
 39‚Üí) {
 40‚Üí    override fun toString(): String =
 41‚Üí        "${operations.joinToString(", ")}(${followedBy.joinToString(";")})"
 42‚Üí}
 43‚Üí
 44‚Üí// TODO: O(size of the resulting parser ^ 2), but can be O(size of the resulting parser)
 45‚Üíinternal fun <T> List<ParserStructure<T>>.concat(): ParserStructure<T> {
 46‚Üí    fun <T> ParserStructure<T>.append(other: ParserStructure<T>): ParserStructure<T> = if (followedBy.isEmpty()) {
 47‚Üí        ParserStructure(operations + other.operations, other.followedBy)
 48‚Üí    } else {
 49‚Üí        ParserStructure(operations, followedBy.map { it.append(other) })
 50‚Üí    }
 51‚Üí    fun <T> ParserStructure<T>.simplify(): ParserStructure<T> {
 52‚Üí        val newOperations = mutableListOf<ParserOperation<T>>()
 53‚Üí        var currentNumberSpan: MutableList<NumberConsumer<T>>? = null
 54‚Üí        // joining together the number consumers in this parser before the first alternative
 55‚Üí        for (op in operations) {
 56‚Üí            if (op is NumberSpanParserOperation) {
 57‚Üí                if (currentNumberSpan != null) {
 58‚Üí                    currentNumberSpan.addAll(op.consumers)
 59‚Üí                } else {
 60‚Üí                    currentNumberSpan = op.consumers.toMutableList()
 61‚Üí                }
 62‚Üí            } else {
 63‚Üí                if (currentNumberSpan != null) {
 64‚Üí                    newOperations.add(NumberSpanParserOperation(currentNumberSpan))
 65‚Üí                    currentNumberSpan = null
 66‚Üí                }
 67‚Üí                newOperations.add(op)
 68‚Üí            }
 69‚Üí        }
 70‚Üí        val mergedTails = followedBy.flatMap {
 71‚Üí            val simplified = it.simplify()
 72‚Üí            // parser `ParserStructure(emptyList(), p)` is equivalent to `p`,
 73‚Üí            // unless `p` is empty. For example, ((a|b)|(c|d)) is equivalent to (a|b|c|d).
 74‚Üí            // As a special case, `ParserStructure(emptyList(), emptyList())` represents a parser that recognizes an empty
 75‚Üí            // string. For example, (|a|b) is not equivalent to (a|b).
 76‚Üí            if (simplified.operations.isEmpty())
 77‚Üí                simplified.followedBy.ifEmpty { listOf(simplified) }
 78‚Üí            else
 79‚Üí                listOf(simplified)
 80‚Üí        }
 81‚Üí        return if (currentNumberSpan == null) {
 82‚Üí            // the last operation was not a number span, or it was a number span that we are allowed to interrupt
 83‚Üí            ParserStructure(newOperations, mergedTails)
 84‚Üí        } else if (mergedTails.none {
 85‚Üí                it.operations.firstOrNull()?.let { it is NumberSpanParserOperation } == true
 86‚Üí            }) {
 87‚Üí            // the last operation was a number span, but there are no alternatives that start with a number span.
 88‚Üí            newOperations.add(NumberSpanParserOperation(currentNumberSpan))
 89‚Üí            ParserStructure(newOperations, mergedTails)
 90‚Üí        } else {
 91‚Üí            val newTails = mergedTails.map {
 92‚Üí                when (val firstOperation = it.operations.firstOrNull()) {
 93‚Üí                    is NumberSpanParserOperation -> {
 94‚Üí                        ParserStructure(
 95‚Üí                            listOf(NumberSpanParserOperation(currentNumberSpan + firstOperation.consumers)) + it.operations.drop(
 96‚Üí                                1
 97‚Üí                            ),
 98‚Üí                            it.followedBy
 99‚Üí                        )
100‚Üí                    }
101‚Üí
102‚Üí                    null -> ParserStructure(
103‚Üí                        listOf(NumberSpanParserOperation(currentNumberSpan)),
104‚Üí                        it.followedBy
105‚Üí                    )
106‚Üí
107‚Üí                    else -> ParserStructure(
108‚Üí                        listOf(NumberSpanParserOperation(currentNumberSpan)) + it.operations,
109‚Üí                        it.followedBy
110‚Üí                    )
111‚Üí                }
112‚Üí            }
113‚Üí            ParserStructure(newOperations, newTails)
114‚Üí        }
115‚Üí    }
116‚Üí    val naiveParser = foldRight(ParserStructure<T>(emptyList(), emptyList())) { parser, acc -> parser.append(acc) }
117‚Üí    return naiveParser.simplify()
118‚Üí}
