120‚Üíinternal interface Copyable<Self> {
121‚Üí    fun copy(): Self
122‚Üí}
123‚Üí
124‚Üí@JvmInline
125‚Üíinternal value class Parser<Output: Copyable<Output>>(
126‚Üí    private val commands: ParserStructure<Output>
127‚Üí) {
128‚Üí    /**
129‚Üí     * [startIndex] is the index of the first character that is not yet consumed.
130‚Üí     *
131‚Üí     * [allowDanglingInput] determines whether the match is only successful if the whole string after [startIndex]
132‚Üí     * is consumed.
133‚Üí     *
134‚Üí     * [onSuccess] is invoked as soon as some parsing attempt succeeds.
135‚Üí     * [onError] is invoked when some parsing attempt fails.
136‚Üí     */
137‚Üí    // Would be a great place to use the `Flow` from `kotlinx.coroutines` here instead of `onSuccess` and
138‚Üí    // `onError`, but alas.
139‚Üí    private inline fun parse(
140‚Üí        input: CharSequence,
141‚Üí        startIndex: Int,
142‚Üí        initialContainer: Output,
143‚Üí        allowDanglingInput: Boolean,
144‚Üí        onError: (ParseError) -> Unit,
145‚Üí        onSuccess: (Int, Output) -> Unit
146‚Üí    ) {
147‚Üí        val parseOptions = mutableListOf(ParserState(initialContainer, commands, startIndex))
148‚Üí        iterate_over_alternatives@while (true) {
149‚Üí            val state = parseOptions.removeLastOrNull() ?: break
150‚Üí            val output = state.output.copy()
151‚Üí            var inputPosition = state.inputPosition
152‚Üí            val parserStructure = state.parserStructure
153‚Üí            run parse_one_alternative@{
154‚Üí                for (ix in parserStructure.operations.indices) {
155‚Üí                    parserStructure.operations[ix].consume(output, input, inputPosition).match(
156‚Üí                        { inputPosition = it },
157‚Üí                        {
158‚Üí                            onError(it)
159‚Üí                            return@parse_one_alternative // continue@iterate_over_alternatives, if that were supported
160‚Üí                        }
161‚Üí                    )
162‚Üí                }
163‚Üí                if (parserStructure.followedBy.isEmpty()) {
164‚Üí                    if (allowDanglingInput || inputPosition == input.length) {
165‚Üí                        onSuccess(inputPosition, output)
166‚Üí                    } else {
167‚Üí                        onError(ParseError(inputPosition) { "There is more input to consume" })
168‚Üí                    }
169‚Üí                } else {
170‚Üí                    for (ix in parserStructure.followedBy.indices.reversed()) {
171‚Üí                        parseOptions.add(ParserState(output, parserStructure.followedBy[ix], inputPosition))
172‚Üí                    }
173‚Üí                }
174‚Üí            }
175‚Üí        }
176‚Üí    }
177‚Üí
178‚Üí    fun match(input: CharSequence, initialContainer: Output, startIndex: Int = 0): Output {
179‚Üí        val errors = mutableListOf<ParseError>()
180‚Üí        parse(input, startIndex, initialContainer, allowDanglingInput = false, { errors.add(it) }, { _, out -> return@match out })
181‚Üí        errors.sortByDescending { it.position }
182‚Üí        // `errors` can not be empty because each parser will have (successes + failures) >= 1, and here, successes == 0
183‚Üí        ParseException(errors.first()).let {
184‚Üí            for (error in errors.drop(1)) {
185‚Üí                it.addSuppressed(ParseException(error))
186‚Üí            }
187‚Üí            throw it
188‚Üí        }
189‚Üí    }
190‚Üí
191‚Üí    fun matchOrNull(input: CharSequence, initialContainer: Output, startIndex: Int = 0): Output? {
192‚Üí        parse(input, startIndex, initialContainer, allowDanglingInput = false, { }, { _, out -> return@matchOrNull out })
193‚Üí        return null
194‚Üí    }
195‚Üí
196‚Üí    private class ParserState<Output>(
197‚Üí        val output: Output,
198‚Üí        val parserStructure: ParserStructure<Output>,
199‚Üí        val inputPosition: Int,
200‚Üí    )
201‚Üí}
202‚Üí
203‚Üíinternal class ParseException(error: ParseError) : Exception("Position ${error.position}: ${error.message()}")
