16‚Üí@Serializable(with = UtcOffsetSerializer::class)
17‚Üípublic actual class UtcOffset(internal val zoneOffset: ZoneOffset) {
18‚Üí    public actual val totalSeconds: Int get() = zoneOffset.totalSeconds
19‚Üí
20‚Üí    override fun hashCode(): Int = zoneOffset.hashCode()
21‚Üí    override fun equals(other: Any?): Boolean = other is UtcOffset && this.zoneOffset == other.zoneOffset
22‚Üí    actual override fun toString(): String = zoneOffset.toString()
23‚Üí
24‚Üí    public actual companion object {
25‚Üí        public actual val ZERO: UtcOffset = UtcOffset(ZoneOffset.UTC)
26‚Üí
27‚Üí        public actual fun parse(input: CharSequence, format: DateTimeFormat<UtcOffset>): UtcOffset = when {
28‚Üí            format === Formats.ISO -> parseWithFormat(input, isoFormat)
29‚Üí            format === Formats.ISO_BASIC -> parseWithFormat(input, isoBasicFormat)
30‚Üí            format === Formats.FOUR_DIGITS -> parseWithFormat(input, fourDigitsFormat)
31‚Üí            else -> format.parse(input)
32‚Üí        }
33‚Üí
34‚Üí        @Deprecated("This overload is only kept for binary compatibility", level = DeprecationLevel.HIDDEN)
35‚Üí        public fun parse(offsetString: String): UtcOffset = parse(input = offsetString)
36‚Üí
37‚Üí        @Suppress("FunctionName")
38‚Üí        public actual fun Format(block: DateTimeFormatBuilder.WithUtcOffset.() -> Unit): DateTimeFormat<UtcOffset> =
39‚Üí            UtcOffsetFormat.build(block)
40‚Üí    }
41‚Üí
42‚Üí    public actual object Formats {
43‚Üí        public actual val ISO: DateTimeFormat<UtcOffset> get() = ISO_OFFSET
44‚Üí        public actual val ISO_BASIC: DateTimeFormat<UtcOffset> get() = ISO_OFFSET_BASIC
45‚Üí        public actual val FOUR_DIGITS: DateTimeFormat<UtcOffset> get() = FOUR_DIGIT_OFFSET
46‚Üí    }
47‚Üí}
48‚Üí
49‚Üí@Suppress("ACTUAL_FUNCTION_WITH_DEFAULT_ARGUMENTS")
50‚Üípublic actual fun UtcOffset(hours: Int? = null, minutes: Int? = null, seconds: Int? = null): UtcOffset =
51‚Üí    try {
52‚Üí        when {
53‚Üí            hours != null ->
54‚Üí                UtcOffset(ZoneOffset.ofHoursMinutesSeconds(hours, minutes ?: 0, seconds ?: 0))
55‚Üí            minutes != null ->
56‚Üí                UtcOffset(ZoneOffset.ofHoursMinutesSeconds(minutes / 60, minutes % 60, seconds ?: 0))
57‚Üí            else -> {
58‚Üí                UtcOffset(ZoneOffset.ofTotalSeconds(seconds ?: 0))
59‚Üí            }
60‚Üí        }
61‚Üí    } catch (e: DateTimeException) {
62‚Üí        throw IllegalArgumentException(e)
63‚Üí    }
64‚Üí
65‚Üíprivate val isoFormat by lazy {
66‚Üí    DateTimeFormatterBuilder().parseCaseInsensitive().appendOffsetId().toFormatter()
67‚Üí}
68‚Üíprivate val isoBasicFormat by lazy {
69‚Üí    DateTimeFormatterBuilder().parseCaseInsensitive().appendOffset("+HHmmss", "Z").toFormatter()
70‚Üí}
71‚Üíprivate val fourDigitsFormat by lazy {
72‚Üí    DateTimeFormatterBuilder().parseCaseInsensitive().appendOffset("+HHMM", "+0000").toFormatter()
73‚Üí}
