75‚Üíprivate fun parseWithFormat(input: CharSequence, format: DateTimeFormatter) = try {
76‚Üí    format.parse(input, ZoneOffset::from).let(::UtcOffset)
77‚Üí} catch (e: DateTimeException) {
78‚Üí    throw DateTimeFormatException(e)
79‚Üí}
