100‚Üí    fun DateTimeFormatBuilder.WithUtcOffset.appendIsoOffsetWithoutZOnZero() {
101‚Üí        offsetHours()
102‚Üí        outputIfNeeded(outputMinute) {
103‚Üí            if (useSeparator) {
104‚Üí                char(':')
