115‚Üí    if (zOnZero) {
116‚Üí        optional("Z") {
117‚Üí            alternativeParsing({
118‚Üí                char('z')
119‚Üí            }) {
120‚Üí                appendIsoOffsetWithoutZOnZero()
121‚Üí            }
122‚Üí        }
123‚Üí    } else {
