157‚Üíinternal class IncompleteUtcOffset(
158‚Üí    override var isNegative: Boolean? = null,
159‚Üí    override var totalHoursAbs: Int? = null,
160‚Üí    override var minutesOfHour: Int? = null,
161‚Üí    override var secondsOfMinute: Int? = null,
162‚Üí) : UtcOffsetFieldContainer, Copyable<IncompleteUtcOffset> {
163‚Üí
164‚Üí    fun toUtcOffset(): UtcOffset {
165‚Üí        val sign = if (isNegative == true) -1 else 1
166‚Üí        return UtcOffset(
167‚Üí            totalHoursAbs?.let { it * sign }, minutesOfHour?.let { it * sign }, secondsOfMinute?.let { it * sign }
168‚Üí        )
169‚Üí    }
170‚Üí
171‚Üí    fun populateFrom(offset: UtcOffset) {
172‚Üí        isNegative = offset.totalSeconds < 0
173‚Üí        val totalSecondsAbs = offset.totalSeconds.absoluteValue
174‚Üí        totalHoursAbs = totalSecondsAbs / 3600
175‚Üí        minutesOfHour = (totalSecondsAbs / 60) % 60
176‚Üí        secondsOfMinute = totalSecondsAbs % 60
177‚Üí    }
178‚Üí
179‚Üí    override fun equals(other: Any?): Boolean =
180‚Üí        other is IncompleteUtcOffset && isNegative == other.isNegative && totalHoursAbs == other.totalHoursAbs &&
181‚Üí            minutesOfHour == other.minutesOfHour && secondsOfMinute == other.secondsOfMinute
182‚Üí
183‚Üí    override fun hashCode(): Int =
184‚Üí        isNegative.hashCode() + totalHoursAbs.hashCode() + minutesOfHour.hashCode() + secondsOfMinute.hashCode()
185‚Üí
186‚Üí    override fun copy(): IncompleteUtcOffset =
187‚Üí        IncompleteUtcOffset(isNegative, totalHoursAbs, minutesOfHour, secondsOfMinute)
