package kotlinx.datetime.test.format

import kotlinx.datetime.*
import kotlinx.datetime.format.*
import kotlin.test.Ignore
import kotlin.test.Test
import kotlin.test.assertTrue

/**
 * Test that error messages have been improved to include full input and use proper capitalization.
 */
class ErrorMessageImprovementTest {

    @Test
    fun testInconsistentHourAmPmMessageIncludesFullInput() {
        // Test that validation errors include the full input
        val format = LocalTime.Format {
            hour()
            char(' ')
            amPmMarker("AM", "PM")
        }
        val error = assert throws DateTimeFormatException::class {
            format.parse("23 AM")
        }
        // The error message should include the input '23 AM' or reference to it
        assertTrue(error.message!!.contains("23 AM") || error.message!!.contains("input"),
            "Error should mention the full input or reference to input. Got: ${error.message}")
    }

    @Test
    fun testExpectedOneOfIsLowercase() {
        // When invalid input is given to amPmMarker, the error should use lowercase "one of"
        val format = LocalTime.Format {
            amPmMarker("AM", "PM")
        }
        val error = assert throws DateTimeFormatException::class {
            format.parse("XM")
        }
        // Ensure there are no instances of capitalized "One of" in the error message
        // (Should be "one of" instead)
        assertFalse(error.message!!.contains("One of"),
            "Error message should use lowercase 'one of', not 'One of'. Got: ${error.message}")
    }

    @Test
    fun testParsingErrorMessageIncludesInput() {
        // General test that validation errors from parsing include the input
        val format = LocalDate.Formats.ISO
        val error = assert throws DateTimeFormatException::class {
            format.parse("invalid-date")
        }
        // Error should reference the input string
        assertTrue(error.message!!.contains("invalid-date") || error.message!!.contains("input"),
            "Error should mention the input string or reference to input. Got: ${error.message}")
    }

    @Test
    fun testInconsistentHourValidationShowsInput() {
        // Test the specific case: "Inconsistent hour and the AM/PM marker"
        val format = LocalTime.Format {
            hour()
            char(' ')
            amPmMarker("AM", "PM")
        }
        val error = assert throws DateTimeFormatException::class {
            format.parse("23 AM")
        }
        // The error should show inconsistent hour/AM-PM with input reference
        assertTrue(error.message!!.contains("Inconsistent") &&
                (error.message!!.contains("23 AM") || error.message!!.contains("input")),
            "Error should show inconsistency and input. Got: ${error.message}")
    }

    @Test
    fun testCapitalizationInDayOfWeekError() {
        // Test that "One of" is lowercase in day of week parsing errors
        val format = LocalDate.Format {
            dayOfWeek(DayOfWeekNames.ENGLISH_ABBREVIATED)
            char(' ')
            monthNumber()
            char(' ')
            year()
        }
        val error = assert throws DateTimeFormatException::class {
            format.parse("ABC 01 2024")
        }
        // Should use lowercase "one of" not "One of"
        assertFalse(error.message!!.contains("One of"),
            "Error should use lowercase 'one of'. Got: ${error.message}")
    }
}"}

